mapper.insert:
INSERT INTO
    TB_ACCESS_LOG
VALUES (
    TO_CHAR(SYSDATE, 'YYYYMMDD')
    , (
        SELECT
            NVL(MAX(SERIAL_NUMBERS), 0) + 1
        FROM
            TB_ACCESS_LOG
        WHERE
            BASE_DAY = TO_CHAR(SYSDATE, 'YYYYMMDD')
    )
    , SYSDATE
    , #{userId}
    , #{userNm}
    , #{privId}
    , #{menuId}
    , #{functionNm}
    , #{methodNm}
    , #{actionContent}
    , #{position}
    , #{parameters}
)
